// 计算每个数据对象到聚类中心的距离
void js_dist(TEAM T[], CENTER C[])
{
    int i;
    for (i = 0; i < 15; i++)
    {
        T[i].dist[0] = sqrt(pow((T[i].score[0] - C[0].a), 2) + pow((T[i].score[1] - C[0].b), 2) + pow((T[i].score[2] - C[0].c), 2));
        T[i].dist[1] = sqrt(pow((T[i].score[0] - C[1].a), 2) + pow((T[i].score[1] - C[1].b), 2) + pow((T[i].score[2] - C[1].c), 2));
        T[i].dist[2] = sqrt(pow((T[i].score[0] - C[2].a), 2) + pow((T[i].score[1] - C[2].b), 2) + pow((T[i].score[2] - C[2].c), 2));
    }
}

// 将每支球队分到最近的簇
void xz_center(TEAM T[])
{
    int i, j;
    double min;
    for (i = 0; i < 15; i++)
    {
        min = T[i].dist[0];
        for (j = 0; j < 3; j++)
        {
            if (T[i].dist[j] < min)
            {
                min = T[i].dist[j];
                T[i].id = j;
            }
        }
    }
}

// 计算簇的新中心
void js_center(TEAM T[], CENTER C[])
{
    int i, count0 = 0, count1 = 0, count2 = 0;
    for (i = 0; i < 3; i++)
    {
        C[i].a = 0;
        C[i].b = 0;
        C[i].c = 0;
    }
    for (i = 0; i < 15; i++)
    {
        if (T[i].id == 0)      // C[0]代表；A簇
        {
            C[0].a += T[i].score[0];
            C[0].b += T[i].score[1];
            C[0].c += T[i].score[2];
            count0++;
        }

        if (T[i].id == 1)      // C[1]代表；B簇
        {
            C[1].a += T[i].score[0];
            C[1].b += T[i].score[1];
            C[1].c += T[i].score[2];
            count1++;
        }

        if (T[i].id == 2)      // C[2]代表；C簇
        {
            C[2].a += T[i].score[0];
            C[2].b += T[i].score[1];
            C[2].c += T[i].score[2];
            count2++;
        }
    }
    C[0].a = C[0].a / count0;
    C[0].b = C[0].b / count0;
    C[0].c = C[0].c / count0;

    C[1].a = C[1].a / count1;
    C[1].b = C[1].b / count1;
    C[1].c = C[1].c / count1;

    C[2].a = C[2].a / count2;
    C[2].b = C[2].b / count2;
    C[2].c = C[2].c / count2;
}

// 比较结果有无变化
void compare(TEAM T[])
{
    i_jix = 0;
    int i, j, temp;
    double min1;
    for (i = 0; i < 15; i++)
    {
        min1 = T[i].dist[0];
        temp = 0;
        for (j = 0; j < 3; j++)
        {
            if (T[i].dist[j] < min1)
            {
                min1 = T[i].dist[j];
                temp = j;
            }
        }
        if (T[i].id != temp)   // 若存在不相同的，则退出循环，并标记i_jix=1
        {
            i_jix = 1;
            break;
        }
    }
}

// 输出结果
void shuchu(TEAM T[])
{
