/* ------------------------------------------------------------------ *
 *  Рисуем составной объект (прямоугольник, треугольник, круг, трапеция)
 * ------------------------------------------------------------------ */
QPixmap MainWindow::drawCompositeShape(const QSize &size)
{
    // Создаём прозрачный пиксмап нужного размера
    QPixmap pix(size);
    pix.fill(Qt::transparent);

    QPainter painter(&pix);
    painter.setRenderHint(QPainter::Antialiasing, true);

    // -------------------------------------------------
    // 1. Прямоугольник (зеленый)
    // -------------------------------------------------
    QRect rect(30, 30, 100, 60);
    painter.setPen(Qt::NoPen);
    painter.setBrush(QColor(100, 200, 100));
    painter.drawRect(rect);

    // -------------------------------------------------
    // 2. Треугольник (красный) – над прямоугольником
    // -------------------------------------------------
    QPolygon triangle;
    triangle << QPoint(rect.left() + rect.width() / 2, rect.top() - 40)   // верхняя вершина
             << QPoint(rect.left(),               rect.top())          // левая
             << QPoint(rect.right(),              rect.top());         // правая
    painter.setBrush(QColor(200, 80, 80));
    painter.drawPolygon(triangle);

    // -------------------------------------------------
    // 3. Окружность (синяя) – справа от прямоугольника
    // -------------------------------------------------
    int radius = 30;
    QPoint circleCenter(rect.right() + radius + 10, rect.center().y());
    painter.setBrush(QColor(80, 120, 200));
    painter.drawEllipse(circleCenter, radius, radius);

    // -------------------------------------------------
    // 4. Трапеция (желтая) – снизу
    // -------------------------------------------------
    QPolygon trapezoid;
    trapezoid << QPoint(rect.left() - 10, rect.bottom() + 30)      // нижняя левая
              << QPoint(rect.right() + 10, rect.bottom() + 30)     // нижняя правая
              << QPoint(rect.right(),    rect.bottom())           // верхняя правая
              << QPoint(rect.left(),     rect.bottom());          // верхняя левая
    painter.setBrush(QColor(240, 210, 80));
    painter.drawPolygon(trapezoid);

    // -------------------------------------------------
    // Если захотите добавить подписи – раскомментируйте:
    // -------------------------------------------------
    // painter.setPen(Qt::black);
    // painter.drawText(rect, Qt::AlignCenter, "RECT");
    // ...

    painter.end();
    return pix;
}

