import psdi.mbo.MboSetRemote;
import psdi.mbo.MboRemote;
import psdi.util.MXException;
import java.rmi.RemoteException;

public class InventoryUtil {

    /**
     * Gets the available inventory balance for a given item and site.
     *
     * @param mboset  - MboSet instance for the INVENTORY object
     * @param itemNum - Item number
     * @param siteId  - Site ID
     * @return Available inventory balance (CURBAL - RESERVEDQTY)
     * @throws MXException
     * @throws RemoteException
     */
    public static double getAvailableInventoryBalance(MboSetRemote mboset, String itemNum, String siteId) 
            throws MXException, RemoteException {

        if (mboset == null || itemNum == null || siteId == null) {
            throw new IllegalArgumentException("MboSet, Item Number, or Site ID cannot be null");
        }

        double availableBalance = 0;

        // Set the qualification to filter inventory records
        String qualification = "ITEMNUM = '" + itemNum + "' AND SITEID = '" + siteId + "'";
        mboset.setWhere(qualification);
        mboset.reset();

        try {
            MboRemote inventoryMbo = mboset.moveFirst();

            if (inventoryMbo != null) {
                double currentBalance = inventoryMbo.getDouble("CURBAL");
                double reservedQty = inventoryMbo.getDouble("RESERVEDQTY");

                availableBalance = currentBalance - reservedQty;
            } else {
                System.out.println("No inventory found for Item: " + itemNum + " at Site: " + siteId);
            }
        } finally {
            // Always close the MboSet to prevent memory leaks
            mboset.close();
        }

        return availableBalance;
    }
}
